// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_fields_representations_cache_2(acceptJson: boolean, etagMatches: boolean, privateData: boolean): { status: number; cacheControl: string; vary: string } {
  if (!acceptJson) return { status: 406, cacheControl: "no-store", vary: "Accept" };
  const cacheControl = privateData ? "private, no-store" : "public, max-age=60";
  const status = etagMatches ? 304 : 200;
  return { status, cacheControl, vary: "Accept, Accept-Encoding" };
}

